func withHTTPMetrics(m *Metrics, next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()
		rw := &statusCapturingResponseWriter{ResponseWriter: w, status: 200}
		next.ServeHTTP(rw, r)
		code := strconv.Itoa(rw.status)
		path := r.URL.Path
		method := r.Method

		m.requestsTotal.WithLabelValues(method, path, code).Inc()
		m.requestDur.WithLabelValues(method, path, code).Observe(time.Since(start).Seconds())

		userID := r.Header.Get("X-User-ID")
		reqID := r.Header.Get("X-Request-ID")
		if userID == "" {
			userID = "unknown"
		}
		if reqID == "" {
			reqID = "unknown"
		}
		m.userRequestsTotal.WithLabelValues(userID, reqID, method, path, code).Inc()
		m.userRequestDur.WithLabelValues(userID, reqID, method, path, code).Observe(time.Since(start).Seconds())
	})
}

