func sanitizeLabels(cfg Config, in map[string]string) (prometheus.Labels, []string, []string, error) {
	if in == nil {
		in = map[string]string{}
	}
	if len(in) > cfg.MaxLabelsPerMetric {
		return nil, nil, nil, fmt.Errorf("too many labels: %d > %d", len(in), cfg.MaxLabelsPerMetric)
	}

	out := make(prometheus.Labels, len(in))
	labelNames := make([]string, 0, len(in))
	for k := range in {
		labelNames = append(labelNames, k)
	}
	sortStrings(labelNames)

	labelValues := make([]string, 0, len(labelNames))
	for _, k := range labelNames {
		v := in[k]
		k = strings.TrimSpace(k)
		if k == "" {
			return nil, nil, nil, fmt.Errorf("label name cannot be empty")
		}
		if len(k) > cfg.MaxLabelNameBytes {
			return nil, nil, nil, fmt.Errorf("label name too long: %s", k)
		}
		if !cfg.AllowLabelNameRegex.MatchString(k) {
			return nil, nil, nil, fmt.Errorf("label name not allowed: %s", k)
		}

		v = strings.TrimSpace(v)
		if len(v) > cfg.MaxLabelValueBytes {
			v = v[:cfg.MaxLabelValueBytes]
		}
		if cfg.HashLabelValues {
			v = hashValue(v, cfg.HashPrefixLen)
		}
		out[k] = v
		labelValues = append(labelValues, v)
	}

	return out, labelNames, labelValues, nil
}

func isValidMetricName(s string) bool {
	if s == "" {
		return false
	}
	for i, r := range s {
		if (r >= 'a' && r <= 'z') || (r >= 'A' && r <= 'Z') || r == '_' || r == ':' || (i > 0 && r >= '0' && r <= '9') {
			continue
		}
		return false
	}
	return true
}

func hashValue(v string, prefixLen int) string {
	sum := sha256.Sum256([]byte(v))
	hexed := hex.EncodeToString(sum[:])
	if prefixLen <= 0 || prefixLen >= len(hexed) {
		return hexed
	}
	return hexed[:prefixLen]
}

func sortStrings(a []string) {
	if len(a) < 2 {
		return
	}
	quickSortStrings(a, 0, len(a)-1)
}

func quickSortStrings(a []string, lo, hi int) {
	for lo < hi {
		i, j := lo, hi
		p := a[(lo+hi)/2]
		for i <= j {
			for a[i] < p {
				i++
			}
			for a[j] > p {
				j--
			}
			if i <= j {
				a[i], a[j] = a[j], a[i]
				i++
				j--
			}
		}
		if j-lo < hi-i {
			if lo < j {
				quickSortStrings(a, lo, j)
			}
			lo = i
		} else {
			if i < hi {
				quickSortStrings(a, i, hi)
			}
			hi = j
		}
	}
}